package main

import (
	"fmt"
	"net/http"
	"io/ioutil"
)

func handler(w http.ResponseWriter, r *http.Request) {
	// Read the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		fmt.Fprintf(w, "Error reading request body: %v", err)
		return
	}

	// Close the request body to release the underlying resources
	defer r.Body.Close()

	// Print the content of the request body
	fmt.Fprintf(w, "Request Content: %s", body)
}

func main() {
	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}
```

This program sets up a simple HTTP server that listens on port `8080`. When a request is received, it reads the request body and prints its content in the response.

